@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_6916e4d4846b4381959a5cdac10ea16e.Models
@using sv_6916e4d4846b4381959a5cdac10ea16e.Services
@inject ApplicationStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply – Personal Info</PageTitle>

<h1>Step 1: Personal Information</h1>

<EditForm Model="model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private PersonalInfo model = new();
    private string sessionId = string.Empty;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext!
            .Request.Cookies["blazor_wizard_session"]!;
        var state = Store.GetOrCreate(sessionId);
        // Copy into a local model so edits aren't committed until "Next"
        model = new PersonalInfo
        {
            Name = state.PersonalInfo.Name,
            Email = state.PersonalInfo.Email
        };
    }

    private void Next()
    {
        var state = Store.GetOrCreate(sessionId);
        state.PersonalInfo = model;
        state.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

