</EditForm>

@code {
    private PersonalInfo model = new();
    private string sessionId = string.Empty;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext!
            .Request.Cookies["blazor_wizard_session"]!;
        var state = Store.GetOrCreate(sessionId);
        // Copy into a local model so edits aren't committed until "Next"
        model = new PersonalInfo
        {
            Name = state.PersonalInfo.Name,
            Email = state.PersonalInfo.Email
        };
    }

    private void Next()
    {
        var state = Store.GetOrCreate(sessionId);
        state.PersonalInfo = model;
        state.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }
}

