 ﻿@inherits LayoutComponentBase
 @using sv_6916e4d4846b4381959a5cdac10ea16e.Services
 @inject NavigationManager Nav
 @inject ApplicationStateStore Store
 @inject IHttpContextAccessor HttpContextAccessor

 <div class="page">
     <div class="sidebar">
         <NavMenu />
     </div>

     <main>
         <div class="top-row px-4">
             <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
         </div>

         @if (IsWizardRoute)
         {
             <div class="wizard-progress px-4 py-3">
                 <div class="d-flex justify-content-between align-items-center mb-2">
                     <strong>Step @CurrentStep of @TotalSteps</strong>
                 </div>
                 <div class="progress mb-3" style="height: 8px;">
                     <div class="progress-bar" role="progressbar"
                          style="width: @(CurrentStep * 100 / TotalSteps)%"></div>
                 </div>
                 <nav class="nav nav-pills nav-fill">
                     @foreach (var step in Steps)
                     {
                         var css = step.Number == CurrentStep ? "nav-link active"
                                 : CompletedSteps.Contains(step.Number) ? "nav-link text-success"
                                 : "nav-link";
                         <a href="@step.Href" class="@css">@step.Label</a>
                     }
                 </nav>
             </div>
         }

         <article class="content px-4">
             @Body
         </article>
     </main>
 </div>

 <div id="blazor-error-ui" data-nosnippet>
     An unhandled error has occurred.
     <a href="." class="reload">Reload</a>
     <span class="dismiss">🗙</span>
 </div>

 @code {
     private const int TotalSteps = 4;

     private record StepInfo(int Number, string Href, string Label);
     private static readonly StepInfo[] Steps =
     [
         new(1, "/apply/personal-info", "Personal Info"),
         new(2, "/apply/experience",    "Experience"),
         new(3, "/apply/references",    "References"),
         new(4, "/apply/review",        "Review"),
     ];

     private bool IsWizardRoute => Nav.Uri.Contains("/apply/", StringComparison.OrdinalIgnoreCase);
     private HashSet<int> CompletedSteps { get; set; } = [];

     private int CurrentStep => Steps.FirstOrDefault(s =>
         Nav.Uri.EndsWith(s.Href, StringComparison.OrdinalIgnoreCase))?.Number ?? 1;

     protected override void OnInitialized()
     {
         var sessionId = HttpContextAccessor.HttpContext?
             .Request.Cookies["blazor_wizard_session"];
         if (sessionId is not null)
         {
             var state = Store.Get(sessionId);
             if (state is not null)
                 CompletedSteps = state.CompletedSteps;
         }
     }
 }
